	async sendDualSessionLists(
		send: (msg: Extract<RelayMessage, { type: "session_list" }>) => void,
		options?: { statuses?: Record<string, SessionStatus> | undefined },
	): Promise<void> {
		const roots = await this.listSessions({
			roots: true,
			statuses: options?.statuses,
