	args: string[];
	options: import("node:child_process").SpawnOptions;
}

// ─── Daemon ─────────────────────────────────────────────────────────────────

export class Daemon {
	port: number;
	private host: string;
	readonly configDir: string;
	readonly socketPath: string;
	readonly logPath: string;
	readonly pidPath: string;

	private httpServer: HttpServer | null = null;
