// ─── Types ──────────────────────────────────────────────────────────────────

export interface DaemonOptions {
	port?: number;
	/** Bind address for the HTTP server (default: "127.0.0.1"). Set to "0.0.0.0" to listen on all interfaces. */
	host?: string;
	configDir?: string;
	socketPath?: string;
	logPath?: string;
