		const result: Array<[string, ProjectReady]> = [];
		for (const [slug, entry] of this.entries) {
			if (entry.status === "ready") {
				result.push([slug, entry]);
			}
		}
		return result;
	}

	slugs(): IterableIterator<string> {
		return this.entries.keys();
