	deps: HandlerDeps,
	clientId: string,
	_payload: PayloadMap["list_sessions"],
): Promise<void> {
	await deps.sessionMgr.sendDualSessionLists((msg) =>
		deps.wsHandler.sendTo(clientId, msg),
	);
}

