	private async broadcastSessionList(): Promise<void> {
		const roots = await this.listSessions({ roots: true });
		this.emit("broadcast", {
			type: "session_list",
			sessions: roots,
			roots: true,
		});

		this.listSessions()
			.then((all) => {
				this.emit("broadcast", {
					type: "session_list",
					sessions: all,
					roots: false,
				});
			})
			.catch((err) => {
				this.log.warn(`Background all-sessions broadcast failed: ${err}`);
			});
