	describe("P5: Delete session (AC4)", () => {
		it("property: deleting a session removes it and emits session_lifecycle", async () => {
			const sessions: MockSession[] = [
				{ id: "ses_a", title: "A", time: { created: 1000, updated: 1000 } },
