			expect(events[0]!.type).toBe("deleted");
		});
	});
});

// ─── Helpers ─────────────────────────────────────────────────────────────────

function dedup(sessions: MockSession[]): MockSession[] {
	const seen = new Set<string>();
	return sessions.filter((s) => {
		if (seen.has(s.id)) return false;
		seen.add(s.id);
		return true;
	});
}

