// ─── handleForkSession Tests (ticket 5.3) ────────────────────────────────────
import { beforeEach, describe, expect, it, vi } from "vitest";
import type { PayloadMap } from "../../../src/lib/handlers/payloads.js";
import {
	handleForkSession,
