	it("determines forkMessageId from last message on whole-session fork", async () => {
		let storedMessageId: string | undefined;
		const forkMeta = {
			setForkEntry: (
				_sid: string,
				entry: { forkMessageId: string; parentID: string },
			) => {
				storedMessageId = entry.forkMessageId;
