		expect(page2.messages).toHaveLength(50);

		// Both pages should have renderedHtml
		for (const msg of [...page1.messages, ...page2.messages]) {
			expect(msg.parts?.[0]?.renderedHtml).toBeDefined();
		}
	});
});

