const _arbMessage = (sessionId: string) =>
	fc.record({
		id: fc.stringMatching(/^msg_[a-z0-9]{4,8}$/),
		role: fc.constantFrom("user", "assistant"),
		sessionID: fc.constant(sessionId),
	});

