						// offset=0: most recent pageSize messages
						const page = await mgr.loadHistory("ses_p", 0);

						expect(page.messages.length).toBe(Math.min(pageSize, msgCount));
						// Cursor-based pagination: hasMore = page.length >= pageSize,
